SELECT COALESCE(SUM(sut_miktari), 0) AS toplam_sut_miktari
FROM sagim_kayitlari
WHERE EXTRACT(YEAR FROM tarih) = 2025;

SELECT COALESCE(SUM(sut_miktari), 0) AS toplam_sut
FROM sagim_kayitlari
WHERE sagim_zamani = 'm';

SELECT SUM(sut_miktari) AS total_evening_milk
FROM sagim_kayitlari
WHERE sagim_zamani = 'e';

SELECT SUM(sut_miktari) AS toplam_sut_miktari
FROM sagim_kayitlari
WHERE tarih = DATE '2025-03-15';
